sp_widget.client_script:
function ($scope, $rootScope, $http, $timeout, $location) {
	var c = this;

	var currentTable = $location.search()['table'];
	var currentPage = $location.search()['id'];
	var label = $location.search()['label'];

	$scope.$on('$locationChangeStart',function(event,current,old){
		var new_page = $location.search()['id'];
		if(new_page != currentPage){
			$('a').not(':contains("acvedsfa")').css("background-color", 'transparent');
		}
	});

	$scope.$on('$locationChangeSuccess', function () {
		// DFCT0010563  - DFCT0010575 
		switch(currentTable){
			case 'x_153465_discovert_task_form_preferences':
			case 'x_153465_discovert_tasker_filters':
				// don't remove new button for these tables.
				// look close at this, the ACL should control this, not a hack like this.
				break;
			default:
				// Hides the new button in the suggested task split-view page
				setTimeout(function(){
					$('button[name="new"]').css('display','none');
				}, 3000);
				break;
		}
	});


	if($("a:contains('"+label+"')").length == 1){
		//KT - RLS - STRY0065050: 04/01/2020
		$("a:contains('"+label+"')" ).css("text-decoration", 'underline');
		//$("a:contains('"+label+"')" ).css("background-color", '#1C2433');
		//$("a:contains('"+label+"')" ).css("color", '#fff');
		//$('a').not(':contains('+label+')').css("background-color", 'transparent');
		$('a').not(':contains('+label+')').css("text-decoration", 'none');
	}
	// DFCT0010563  - DFCT0010575 
	switch(currentTable){
		case 'x_153465_discovert_task_form_preferences':
		case 'x_153465_discovert_tasker_filters':
			// don't remove new button for these tables.
			// look close at this, the ACL should control this, not a hack like this.
			break;

		default:
			// Hides the new button in the suggested task split-view page
			setTimeout(function(){
				$('button[name="new"]').css('display','none');
			}, 3000);
			break;
	}

	// Adds the page title to the split-view pages based on the label parameter from the url	
	$(".panel-heading .panel-title.ng-binding" ).html(label);

}

